def read_prs(path: Path) -> Generator[PRRecord, None, None]:
    with open(path, encoding="utf-8") as f:
        yield from (
            _parse_row(row)
            for row in csv.DictReader(f)
            if _is_valid(row)
        )

def filter_by_state(state: str) -> Callable[[PRRecord], bool]:
    return lambda pr: pr.state == state.lower().strip()

def count_by_language(prs: tuple[PRRecord, ...]) -> dict[str, int]:
    return reduce(
        lambda acc, pr: acc | {pr.language: acc.get(pr.language, 0) + 1},
        prs, {}
    )

@given(st.lists(st.from_type(PRRecord)))
def test_count_never_loses_prs(prs: list[PRRecord]) -> None:
    counts = count_by_language(tuple(prs))
    assert sum(counts.values()) == len(prs)

def make_cache_key(*args: str) -> str:
    return hashlib.sha256("\x00".join(args).encode()).hexdigest()

def compose(*fns: Callable) -> Callable:
    return reduce(lambda f, g: lambda x: g(f(x)), fns, lambda x: x)
